#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int S,X,Y,Z; scanf("%d %d %d %d", &S, &X, &Y, &Z);
        int free = S - (X + Y);
        if(free >= Z) printf("0\n");
        else if(S - X >= Z) printf("1\n");
        else printf("2\n");
    }
    return 0;
}

