import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        S = int(next(it)); X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        free = S - (X + Y)
        if free >= Z:
            out.append('0')
        elif S - X >= Z:
            out.append('1')
        else:
            out.append('2')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

